mapper.select:
SELECT report_id, user_id, analysis_cache_id, title, status, created_at, updated_at, deleted_at
FROM report_history
WHERE user_id = #{userId}
  AND analysis_cache_id = #{analysisCacheId}

SELECT report_id, user_id, analysis_cache_id, title, status, created_at, updated_at, deleted_at
FROM report_history
WHERE user_id = #{userId}
  AND report_id = #{reportId}

SELECT report_id, user_id, analysis_cache_id, title, status, created_at, updated_at, deleted_at
FROM report_history
WHERE user_id = #{userId}
  AND deleted_at IS NULL
ORDER BY created_at DESC, report_id DESC
LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE report_history
SET deleted_at = NULL,
    updated_at = NOW()
WHERE user_id = #{userId}
  AND analysis_cache_id = #{analysisCacheId}

UPDATE report_history
SET deleted_at = NOW(),
    updated_at = NOW()
WHERE user_id = #{userId}
  AND report_id = #{reportId}
  AND deleted_at IS NULL
